    function toBase36(num: number): string {
        if (num === 0) return '0';
        let digits = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ';
        let result = '';
        while (num > 0) {
            let remainder = num % 36;
            result = digits[remainder] + result;
            num = Math.floor(num / 36);
        }
        return result;
    }
    const n2 = n * n;
    const n3 = n * n * n;
    const hex = n2.toString(16).toUpperCase();
    const base36 = toBase36(n3);
    return hex + base36;
}

